#!/bin/bash
set -e

# Clone repo fresh, add missing files, push
cd /tmp
rm -rf mnemo-fix
git clone https://github.com/ggontee/mnemo-app.git mnemo-fix
cd mnemo-fix

mkdir -p "src/app/api/output-research"
echo "" | base64 -d > "src/app/api/output-research/route.ts"

mkdir -p "src/app/api/output-research/save-card"
echo "" | base64 -d > "src/app/api/output-research/save-card/route.ts"

mkdir -p "src/app/api/wiki/generate"
echo "" | base64 -d > "src/app/api/wiki/generate/route.ts"

mkdir -p "src/components"
echo "" | base64 -d > "src/components/Navigation.tsx"

mkdir -p "src/components"
echo "" | base64 -d > "src/components/TagCloud.tsx"

mkdir -p "src/components"
echo "" | base64 -d > "src/components/ThemeDetail.tsx"

mkdir -p "src/lib"
echo "" | base64 -d > "src/lib/data.ts"

mkdir -p "src/lib"
echo "" | base64 -d > "src/lib/types.ts"

git add -A
git commit -m "fix: 누락된 8개 파일 추가 (output-research, wiki/generate, Navigation 등)"
git push origin main
cd /
rm -rf /tmp/mnemo-fix
echo "완료!"